using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver (resolves any type)
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() — strongly-typed metadata access
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> => Type: {personInfo.Type.Name}, Kind: {personInfo.Kind}");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) TryGetTypeInfo<T>() — check-without-throwing
// This succeeds because Person is resolvable via reflection:
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
{
    Console.WriteLine($"\nTryGetTypeInfo<Person> succeeded: {info!.Type.Name}");
}

// Now use a source-gen context that only knows about Person.
// Querying for an unregistered type (int[]) returns false — no exception.
var limited = new JsonSerializerOptions { TypeInfoResolver = AppJsonContext.Default };

if (limited.TryGetTypeInfo<int[]>(out JsonTypeInfo<int[]>? arrayInfo))
{
    Console.WriteLine($"\nTryGetTypeInfo<int[]> succeeded (unexpected)");
}
else
{
    Console.WriteLine($"\nTryGetTypeInfo<int[]> returned false — metadata not available (no exception thrown)");
}

// Confirm it does resolve the type the context knows about:
if (limited.TryGetTypeInfo<Person>(out var personInfo2))
{
    Console.WriteLine($"TryGetTypeInfo<Person> on limited context succeeded: {personInfo2!.Type.Name}");
}

// --- Types ---------------------------------------------------------------

public record Person(string Name, int Age);

